VALUES
  ('pukao-6f0ba476-moex-00019', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '某公司採用定期盤存制與加權平均法，期初有商品3單位單價為$500，本期又進貨7單位單價為 $700，期末剩下2單位。請問期末存貨價值為？', '["$1,000", "$1,280", "$1,300", "$1,400"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00020', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年4月1日以$10,000購入一項設備，估計使用年限為5年，殘值為$1,000。計算X1 年底止的第一年折舊費用，分別採用以下三種折舊方法：⑴直線法，⑵年數合計法，以及⑶倍數 （雙倍）餘額遞減法', '["直線法$1,350；年數合計法$1,800；倍數（雙倍）餘額遞減法$3,000", "直線法$1,350；年數合計法$2,250；倍數（雙倍）餘額遞減法$3,000", "直線法$1,800；年數合計法$2,400；倍數（雙倍）餘額遞減法$3,200", "直線法$1,350；年數合計法$2,160；倍數（雙倍）餘額遞減法$2,880"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00021', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年底編製財務報表時，經帳齡分析後估計應收帳款中有$5,000將無法收回，因而報 導「備抵壞帳」為$5,000。到了X2年，該公司實際沖銷了$8,000的應收帳款，並於X2年底再次 根據帳齡分析，估計應收帳款中仍有$22,000將無法收回。請問：X2年應認列「壞帳費用」為何？ X2年底「備抵壞帳」餘額應為多少？', '["壞帳費用$22,000，備抵壞帳$14,000", "壞帳費用$25,000，備抵壞帳$22,000", "壞帳費用$19,000，備抵壞帳$22,000", "壞帳費用$17,000，備抵壞帳$22,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00022', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年發生以下商品交易（單位：件）： 1月1日：期初存貨100件，單位成本$10 3月1日：進貨200件，單位成本$12 7月1日：銷貨250件 11月1日：進貨100件，單位成本$13 已知該公司採用先進先出法計算存貨成本。請問：截至X1年12月31日，銷貨成本與期末存貨 金額為何？', '["銷貨成本$2,800，期末存貨$1,900", "銷貨成本$2,600，期末存貨$2,100", "銷貨成本$2,900，期末存貨$1,800", "銷貨成本$2,700，期末存貨$2,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00023', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '關於庫藏股票的會計處理與表達，下列何者正確？', '["庫藏股票屬於資產增項，其正常餘額為借方", "庫藏股票屬於資產減項，其正常餘額為貸方", "庫藏股票屬於權益增項，其正常餘額為借方", "庫藏股票屬於權益減項，其正常餘額為借方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00024', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', '甲未婚，對其外甥乙尤其疼愛。甲為激勵乙參加律師考試，在民國（下
同）108 年 8 月 1 日向乙表示：「若汝考上律師，將吾所有之 A 地贈與
汝。」乙向甲表示感謝並為允諾，且該贈與契約經公證。乙接連4 年考
試失利，未能考上律師。甲以為乙已無望考取，在 113 年 6月將A地賣
給善意之丙，並辦妥 A 地所有權之移轉登記，而乙於 113 年 12 月順利
考取律師。試問：
甲、乙間之 A地贈與契約何時發生效力？（10分）
乙請求甲丙塗銷 A 地之所有權登記，並向甲主張 A 地應移轉登記並
交付予乙，是否有理由？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00025', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', '甲為鰥夫，育有乙、丙、丁三子。甲年老亡故後，留有 A地一筆，由乙、
丙、丁三人共同繼承。乙、丙、丁對 A地應如何分割爭論不斷，遲遲未
能達成協議，彼此間存有芥蒂，對 A地未予管理。A地之鄰居戊擅自占
用 A 地使用，後為乙獲悉。試問：乙請求戊返還 A 地於全體公同共有
人，有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00026', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '17歲甲男瞞著父母，授與好友乙代理權，代其承租房屋。乙以甲之名義向房東丙承租H屋，即日 起租，租金每月新臺幣1萬元。下列敘述，何者正確？', '["該授權行為無效", "該H屋租賃契約無效", "該授權行為效力未定", "該H屋租賃契約有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00027', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於法律行為效力之敘述，何者錯誤？', '["甲乙間成立之器官買賣契約無效，且自始無效", "已成立生效之契約，若一方表意人事後以意思表示錯誤撤銷其意思表示者，撤銷後之契約，視 為自始無效", "經承認之法律行為，法律行為自承認權人之承認時起，開始生效", "須經法定代理人同意之契約，若法定代理人事後不承認該契約，則該契約自始無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00028', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲受法院輔助宣告，依民法規定，下列何種法律行為，甲不須經輔助人同意？', '["買賣汽車", "受讓土地所有權", "向銀行貸款", "拋棄繼承權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
